def classify_severity(item: DebtItem) -> Severity:
    """
    Auto-classifies severity based on interest rate and category.
    Human review is always required before the classification is finalized.
    """
    if item.interest_rate == "critical":
        return "S1"
    if item.category == "security_debt":
        return "S1"
    if item.interest_rate == "high" and item.category in ("eval_debt", "prompt_debt"):
        return "S1"
    if item.interest_rate == "high":
        return "S2"
    if item.interest_rate == "medium" and item.category == "eval_debt":
        return "S2"
    if item.interest_rate == "medium":
        return "S3"
    return "S4"

for item in register:
    suggested = classify_severity(item)
    match = "✅" if suggested == item.severity else "⚠️ review needed"
    print(f"{item.id}: suggested={suggested}, actual={item.severity} {match}")
